// Pastikan data berupa array dan memiliki minimal 8 elemen
if (Array.isArray(data) && data.length >= 8) {
    var tahun   = data[0];
    var bulan   = data[1];
    var tanggal = data[2];
    var dow     = data[3];
    var jam     = data[4];
    var menit   = data[5];
    var detik   = data[6];
    var suhu    = data[7];

    // Fungsi helper untuk menambahkan angka 0 di depan (misal: 5 menjadi 05)
    function pad(num) {
        return (num < 10 ? '0' : '') + num;
    }

    // Format teks Jam dan Tanggal
    var teksJam = pad(jam) + ":" + pad(menit) + ":" + pad(detik);
    var teksTanggal = pad(tanggal) + "/" + pad(bulan) + "/20" + pad(tahun);

    // Kirim ke output masing-masing node UI
    return [
        { payload: teksJam },     // Output 1: Ke UI Jam
        { payload: teksTanggal }, // Output 2: Ke UI Tanggal
        { payload: suhu + " °C" }  // Output 3: Ke UI Suhu
    ];
}
return null;

// Mengambil data object dari Modbus
var data = msg.payload;

// Pastikan data tidak kosong dan memiliki properti register yang dibutuhkan
if (data && data.register_30011 !== undefined) {

    // Pemetaan data berdasarkan nama register object baru
    var tahun   = data.register_30011; // Nilai: 26 (Tahun 2026)
    var bulan   = data.register_30012; // Nilai: 6
    var tanggal = data.register_30013; // Nilai: 16
    var dow     = data.register_30014; // Nilai: 2 (Day of Week)
    var jam     = data.register_30015; // Nilai: 20
    var menit   = data.register_30016; // Nilai: 57
    var detik   = data.register_30017; // Nilai: 15
    var suhu    = data.register_30018; // Nilai: 31 (Suhu)

    // Array helper untuk mengubah angka DOW menjadi nama hari
    // (Asumsi standar PLC: 1 = Senin, 2 = Selasa, dst. Sesuaikan jika berbeda)
    var daftarHari = ["", "Senin", "Selasa", "Rabu", "Kamis", "Jumat", "Sabtu", "Minggu"];
    var namaHari = daftarHari[dow] || "Hari Kustom";

    // Fungsi helper untuk menambahkan angka 0 di depan (misal: 6 menjadi 06)
    function pad(num) {
        return (num < 10 ? '0' : '') + num;
    }

    // Format teks Jam, Tanggal + Hari, dan Status Modbus
    var teksJam = pad(jam) + ":" + pad(menit) + ":" + pad(detik);
    var teksTanggal = namaHari + ", " + pad(tanggal) + "/" + pad(bulan) + "/20" + pad(tahun);

    // Cek status modbus untuk visualisasi indikator
    var statusIcon = (data.modbus_status === "success") ? "🟢 OK" : "🔴 ERROR";

    // Kirim ke output masing-masing node UI Dashboard 2
    return [
        { payload: "⏰ " + teksJam },               // Output 1: Ke UI Jam
        { payload: "📅 " + teksTanggal },           // Output 2: Ke UI Tanggal & Hari
        { payload: "🌡️ " + suhu + " °C" },            // Output 3: Ke UI Suhu
        { payload: "🔗 Modbus: " + statusIcon }     // Output 4: Ke UI Status Koneksi (Opsional)
    ];
}
return null;

